SELECT rk.reference_id, l.language_name, l.framework_name
FROM reference_kinds rk
JOIN languages l ON rk.language_id = l.language_id;

SELECT member_id, member_signature
FROM members
WHERE language_id = 1 AND reference_id = 0;

SELECT descriptive_name
FROM descriptive_names
WHERE language_id = [language_id] AND reference_id = [reference_id];

SELECT scope_id, scope_name 
FROM scopes 
WHERE language_id = 1;

SELECT COUNT(*)
FROM type_validations
WHERE validation_rule LIKE '%integer%';

SELECT endpoint_name
FROM api_endpoints
WHERE language_id = 1;

SELECT reference_type
FROM reference_kinds
WHERE reference_id IN (
  SELECT reference_id
  FROM api_endpoints
);

SELECT COUNT(DISTINCT behavior_signature)
FROM behaviors
WHERE language_id = 1;
